import React, { useEffect, useState } from "react";
import "./nhanvien.css";
import { fetchWithAuth } from "../../ultils/request";

function Nhanvien() {
  const [employees, setEmployees] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);
  const [employeeForm, setEmployeeForm] = useState({
    id: "",
    name: "",
    username: "",
    password: "",
    role: "",
    phonenumber: "",
    email: "",
    address: "",
    salary: "",
    salarybonus: "",
    defaultsalary: "",
    carsoldtotal: "",
  });
  const [editMode, setEditMode] = useState(false);
  const [openModal, setOpenModal] = useState(false);

  // Fetch all employees
  const fetchEmployees = async () => {
    setLoading(true);
    try {
      const data = await fetchWithAuth("/api/employees");
      setEmployees(data || []);
    } catch (error) {
      setError(error.message);
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    fetchEmployees();
  }, []);

  // Handle input changes
  const handleInputChange = (e) => {
    const { name, value } = e.target;
    setEmployeeForm({ ...employeeForm, [name]: value });
  };

  // Add or update employee
  const handleAddOrUpdateEmployee = async (e) => {
    e.preventDefault();

    const url = editMode
      ? `/api/employees/${employeeForm.id}`
      : "/api/employees";
    const method = editMode ? "PUT" : "POST";

    try {
      await fetchWithAuth(url, method, employeeForm);
      await fetchEmployees(); // Refresh employee list
      resetForm();
      setOpenModal(false);
    } catch (error) {
      setError(error.message);
    }
  };

  // Delete employee
  const handleDelete = async (id) => {
    try {
      await fetchWithAuth(`/api/employees/${id}`, "DELETE");
      await fetchEmployees(); // Refresh employee list
    } catch (error) {
      setError(error.message);
    }
  };

  // Edit employee
  const handleEdit = (employee) => {
    setEditMode(true);
    setEmployeeForm(employee);
    setOpenModal(true);
  };

  // Reset form
  const resetForm = () => {
    setEmployeeForm({
      id: "",
      name: "",
      username: "",
      password: "",
      role: "",
      phonenumber: "",
      email: "",
      address: "",
      salary: "",
      salarybonus: "",
      defaultsalary: "",
      carsoldtotal: "",
    });
    setEditMode(false);
  };

  if (loading) return <p>Loading...</p>;

  return (
    <div className="customer-table">
      <h2>Bảng Nhân Viên</h2>
      <button onClick={() => setOpenModal(true)} style={{ cursor: "pointer" }}>
        + Nhân viên mới
      </button>
      {openModal && (
        <form onSubmit={handleAddOrUpdateEmployee} className="add-employee-form">
          <div className="add-employee-form--body">
            <input
              type="text"
              name="name"
              placeholder="Tên nhân viên"
              value={employeeForm.name}
              onChange={handleInputChange}
              required
            />
            <input
              type="text"
              name="username"
              placeholder="Tên đăng nhập"
              value={employeeForm.username}
              onChange={handleInputChange}
              required
            />
            {!editMode && (
              <input
                type="password"
                name="password"
                placeholder="Mật khẩu"
                value={employeeForm.password}
                onChange={handleInputChange}
                required
              />
            )}
            <input
              type="text"
              name="role"
              placeholder="Chức vụ"
              value={employeeForm.role}
              onChange={handleInputChange}
              required
            />
            <input
              type="text"
              name="phonenumber"
              placeholder="Số điện thoại"
              value={employeeForm.phonenumber}
              onChange={handleInputChange}
              required
            />
            <input
              type="email"
              name="email"
              placeholder="Email"
              value={employeeForm.email}
              onChange={handleInputChange}
              required
            />
            <input
              type="text"
              name="address"
              placeholder="Địa chỉ"
              value={employeeForm.address}
              onChange={handleInputChange}
              required
            />
            <input
              type="text"
              name="salary"
              placeholder="Lương"
              value={employeeForm.salary}
              onChange={handleInputChange}
              required
            />
            <input
              type="text"
              name="salarybonus"
              placeholder="Lương thưởng"
              value={employeeForm.salarybonus}
              onChange={handleInputChange}
              required
            />
            <input
              type="text"
              name="defaultsalary"
              placeholder="Lương mặc định"
              value={employeeForm.defaultsalary}
              onChange={handleInputChange}
              required
            />
            <input
              type="text"
              name="carsoldtotal"
              placeholder="Số xe bán được"
              value={employeeForm.carsoldtotal}
              onChange={handleInputChange}
              required
            />
            <div className="group-btn">
              <button type="submit">{editMode ? "Cập nhật" : "Thêm"}</button>
              <button
                type="button"
                onClick={() => {
                  resetForm();
                  setOpenModal(false);
                }}
              >
                Hủy
              </button>
            </div>
          </div>
        </form>
      )}
      <table>
        <thead>
          <tr>
            <th>Tên nhân viên</th>
            <th>Chức vụ</th>
            <th>Số điện thoại</th>
            <th>Email</th>
            <th>Địa chỉ</th>
            <th>Lương</th>
            <th>Lương thưởng</th>
            <th>Lương mặc định</th>
            <th>Số xe bán được</th>
            <th>Hành động</th>
          </tr>
        </thead>
        <tbody>
          {employees.map((employee) => (
            <tr key={employee.id}>
              <td>{employee.name}</td>
              <td>{employee.role}</td>
              <td>{employee.phonenumber}</td>
              <td>{employee.email}</td>
              <td>{employee.address}</td>
              <td>{employee.salary}</td>
              <td>{employee.salarybonus}</td>
              <td>{employee.defaultsalary}</td>
              <td>{employee.carsoldtotal}</td>
              <td>
                <button onClick={() => handleEdit(employee)}>Sửa</button>
                <button onClick={() => handleDelete(employee.id)}>Xóa</button>
              </td>
            </tr>
          ))}
        </tbody>
      </table>
      {error && <p className="error">{error}</p>}
    </div>
  );
}

export default Nhanvien;
